import React, { useState } from "react";
import axios from "axios";
import { motion, AnimatePresence } from "framer-motion";

import districtOptions from "../data/district_options.json";
import commodityOptions from "../data/commodity_options.json";

const CropPriceLookup = () => {
    const [district, setDistrict] = useState("");
    const [commodity, setCommodity] = useState("");
    const [prices, setPrices] = useState(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    const fetchPrices = async () => {
        if (!commodity || !district) {
            setError("Please select both commodity and district.");
            return;
        }

        setLoading(true);
        setError("");

        try {
            const response = await axios.post("http://localhost:5000/api/crops/getPrices", {
                Commodity: commodity,
                District: district,
            });
            setPrices(response.data);
        } catch (err) {
            setError("Failed to fetch price data.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-green-50 via-blue-50 to-purple-50 p-4">
            <motion.div 
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.5 }}
                className="w-full max-w-2xl bg-white rounded-2xl shadow-2xl overflow-hidden"
            >
                <div className="bg-gradient-to-r from-green-500 via-blue-500 to-purple-600 p-8">
                    <motion.h2 
                        initial={{ y: -20 }}
                        animate={{ y: 0 }}
                        transition={{ duration: 0.5 }}
                        className="text-4xl font-bold text-center text-white mb-8 drop-shadow-lg"
                    >
                        🌾 Crop Price Lookup 🌾
                    </motion.h2>
                    
                    <motion.div 
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        transition={{ duration: 0.5, delay: 0.2 }}
                        className="space-y-6"
                    >
                        <motion.select 
                            whileFocus={{ scale: 1.02 }}
                            transition={{ duration: 0.2 }}
                            value={commodity} 
                            onChange={(e) => setCommodity(e.target.value)} 
                            className="w-full p-4 border-2 border-white/20 rounded-xl bg-white/10 backdrop-blur-sm text-white placeholder-white/70 shadow-lg focus:ring-2 focus:ring-white/50 hover:bg-white/20 transition-all duration-300"
                        >
                            <option value="" className="text-gray-900">Select Commodity</option>
                            {commodityOptions.map((item, index) => (
                                <option key={index} value={item} className="text-gray-900">{item}</option>
                            ))}
                        </motion.select>

                        <motion.select 
                            whileFocus={{ scale: 1.02 }}
                            transition={{ duration: 0.2 }}
                            value={district} 
                            onChange={(e) => setDistrict(e.target.value)} 
                            className="w-full p-4 border-2 border-white/20 rounded-xl bg-white/10 backdrop-blur-sm text-white placeholder-white/70 shadow-lg focus:ring-2 focus:ring-white/50 hover:bg-white/20 transition-all duration-300"
                        >
                            <option value="" className="text-gray-900">Select District</option>
                            {districtOptions.map((item, index) => (
                                <option key={index} value={item} className="text-gray-900">{item}</option>
                            ))}
                        </motion.select>
                    </motion.div>
                    
                    <motion.button 
                        onClick={fetchPrices} 
                        whileHover={{ scale: 1.05, boxShadow: "0 8px 16px rgba(0,0,0,0.2)" }}
                        whileTap={{ scale: 0.95 }}
                        className="w-full mt-8 p-4 bg-white text-gray-900 font-bold rounded-xl shadow-xl hover:bg-gray-100 transition-all duration-300"
                    >
                        🔍 Get Prices
                    </motion.button>
                    
                    <AnimatePresence>
                        {loading && (
                            <motion.p 
                                initial={{ opacity: 0 }}
                                animate={{ opacity: 1 }}
                                exit={{ opacity: 0 }}
                                className="text-center mt-4 text-white animate-pulse"
                            >
                                Loading...
                            </motion.p>
                        )}
                        {error && (
                            <motion.p 
                                initial={{ opacity: 0, y: -10 }}
                                animate={{ opacity: 1, y: 0 }}
                                exit={{ opacity: 0, y: -10 }}
                                className="text-center mt-4 text-red-200 font-bold"
                            >
                                {error}
                            </motion.p>
                        )}
                    </AnimatePresence>
                </div>

                <AnimatePresence>
                    {prices && (
                        <motion.div 
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            exit={{ opacity: 0, y: -20 }}
                            transition={{ duration: 0.3 }}
                            className="p-8 bg-white"
                        >
                            <motion.h3 
                                initial={{ opacity: 0 }}
                                animate={{ opacity: 1 }}
                                transition={{ delay: 0.2 }}
                                className="text-2xl font-semibold text-gray-800 text-center mb-6"
                            >
                                Price Details
                            </motion.h3>
                            <div className="grid gap-4 md:grid-cols-2">
                                {prices.map((data, index) => (
                                    <motion.div
                                        key={index}
                                        initial={{ opacity: 0, x: -20 }}
                                        animate={{ opacity: 1, x: 0 }}
                                        transition={{ delay: index * 0.1 }}
                                        whileHover={{ 
                                            scale: 1.02,
                                            boxShadow: "0 4px 8px rgba(0,0,0,0.1)",
                                            zIndex: 1
                                        }}
                                        className="p-6 bg-gradient-to-br from-yellow-50 to-orange-50 shadow-lg rounded-xl border border-orange-100 relative transform transition-all duration-300"
                                    >
                                        <div className="space-y-3">
                                            <p className="font-semibold text-lg text-gray-800">
                                                <span className="text-orange-600">Grade:</span> {data.Grade}
                                            </p>
                                            <p className="text-gray-700">
                                                <span className="text-orange-600">Min Price:</span> {data["Min Price"]} ₹
                                            </p>
                                            <p className="text-gray-700">
                                                <span className="text-orange-600">Max Price:</span> {data["Max Price"]} ₹
                                            </p>
                                            <p className="text-gray-700">
                                                <span className="text-orange-600">Modal Price:</span> {data["Modal Price"]} ₹
                                            </p>
                                        </div>
                                    </motion.div>
                                ))}
                            </div>
                        </motion.div>
                    )}
                </AnimatePresence>
            </motion.div>
        </div>
    );
};

export default CropPriceLookup;
